// Preprocess: validate and prepare text
const text = $input.first().json.body?.text || $input.first().json.text || '';

if (!text || text.trim().length === 0) {
  throw new Error('No text provided');
}

// Approximate token count (1 token ≈ 4 chars)
const approxTokens = Math.ceil(text.length / 4);
const maxInputTokens = 100000;

let processedText = text;
if (approxTokens > maxInputTokens) {
  processedText = text.substring(0, maxInputTokens * 4);
}

return [{
  json: {
    text: processedText,
    originalLength: text.length,
    wasTruncated: text.length !== processedText.length
  }
}];

