// Parse Groq's LLM response
const response = $input.first().json;

try {
  const content = response.choices[0].message.content;
  const analysis = typeof content === 'string' ? JSON.parse(content) : content;

  const result = {
    overall_sentiment: analysis.overall_sentiment || 'NEUTRAL',
    confidence: analysis.confidence ?? 0.5,
    language_detected: analysis.language_detected || 'ENGLISH',
    satisfaction_score: analysis.satisfaction_score ?? 50,
    urgency_level: analysis.urgency_level || 'LOW',
    sentiment_trend: analysis.sentiment_trend || 'Stable',
    summary: analysis.summary || 'Analysis complete',
    sentences: analysis.sentences || [],
    topics: analysis.topics || {},
    emotions: analysis.emotions || {}
  };

  return [{ json: result }];
} catch (error) {
  return [{
    json: {
      error: 'Failed to parse LLM response',
      message: error.message,
      overall_sentiment: 'NEUTRAL',
      confidence: 0,
      sentences: [],
      topics: {},
      emotions: {}
    }
  }];
}
